class LuaStdlibTest {
    @Test
    fun `openBase installs type and tostring globals`() {
        val state = LuaState.create()
        LuaStdlib.openBase(state)

        assertEquals(
            LuaStatus.OK,
            state.load(
                """
                return type(nil), type(false), type(1), type("x"), type({}),
                    tostring(nil), tostring(false), tostring(12), tostring("ok")
                """.trimIndent(),
                "stdlib-base.lua",
            ),
        )
        assertEquals(LuaStatus.OK, state.pcall(0, -1))

        assertEquals("nil", state.toString(1))
        assertEquals("boolean", state.toString(2))
        assertEquals("number", state.toString(3))
        assertEquals("string", state.toString(4))
        assertEquals("table", state.toString(5))
        assertEquals("nil", state.toString(6))
        assertEquals("false", state.toString(7))
        assertEquals("12", state.toString(8))
        assertEquals("ok", state.toString(9))
    }

    @Test
    fun `openBase installs lua 55 version global`() {
        val defaultState = LuaState.create()
        LuaStdlib.openBase(defaultState)

        assertEquals(LuaStatus.OK, defaultState.load("""return _VERSION""", "version-default.lua"))
        assertEquals(LuaStatus.OK, defaultState.pcall(0, -1))
        assertEquals("Lua 5.5", defaultState.toString(1))
    }

    @Test
    fun `openBase preserves every base function identity across reopen`() {
        val state = LuaState.create()
        LuaStdlib.openBase(state)

        assertEquals(
            LuaStatus.OK,
            state.load(
                """
                baseNames = {
                    "assert", "collectgarbage", "dofile", "error", "getmetatable", "ipairs",
                    "loadfile", "load", "next", "pairs", "pcall", "print", "warn", "rawequal",
                    "rawlen", "rawget", "rawset", "select", "setmetatable", "tonumber", "tostring",
                    "type", "xpcall",
                }
                savedBaseFunctions = {}
                for index = 1, #baseNames do
                    local name = baseNames[index]
                    savedBaseFunctions[name] = _G[name]
                end
                savedGlobalTable = _G
                """.trimIndent(),
                "base-identity-before-reopen.lua",
            ),
        )
        assertEquals(LuaStatus.OK, state.pcall(0, 0), state.toString(-1))

        LuaStdlib.openBase(state)
        assertEquals(
            LuaStatus.OK,
            state.load(
                """
                local mismatch = ""
                for index = 1, #baseNames do
                    local name = baseNames[index]
                    if savedBaseFunctions[name] ~= _G[name] then
                        mismatch = mismatch .. name .. ","
                    end
                end
                return mismatch, savedGlobalTable == _G, _VERSION
                """.trimIndent(),
                "base-identity-after-reopen.lua",
            ),
        )
        assertEquals(LuaStatus.OK, state.pcall(0, -1), state.toString(-1))

        assertEquals("", state.toString(1))
        assertTrue(state.toBoolean(2))
        assertEquals("Lua 5.5", state.toString(3))
    }

    @Test
    fun `tostring uses table tostring metamethods`() {
        val state = LuaState.create()
        LuaStdlib.openBase(state)

        assertEquals(
            LuaStatus.OK,
            state.load(
                """
                local named = setmetatable({name = "value"}, {
                    __tostring = function(value)
                        return "table:" .. value.name
                    end,
                })
                local numeric = setmetatable({}, {
                    __tostring = function()
                        return 42
                    end,
                })
                local protected = setmetatable({}, {
                    __metatable = "locked",
                    __tostring = function()
                        return "hidden"
                    end,
                })
                return tostring(named), tostring(numeric), tostring(protected), getmetatable(protected)
                """.trimIndent(),
                "tostring-metamethod.lua",
            ),
        )
        assertEquals(LuaStatus.OK, state.pcall(0, -1), state.toString(-1))

        assertEquals("table:value", state.toString(1))
        assertEquals("42", state.toString(2))
        assertEquals("hidden", state.toString(3))
        assertEquals("locked", state.toString(4))
    }

    @Test
    fun `tostring formats numbers like lua`() {
        val state = LuaState.create()
        LuaStdlib.openBase(state)

        assertEquals(
            LuaStatus.OK,
            state.load(
                """
                local numeric = setmetatable({}, {
                    __tostring = function()
                        return 1e15
                    end,
                })
                return tostring(1),
                    tostring(1.0),
                    tostring(1.25),
                    tostring(1e14),
                    tostring(1e15),
                    tostring(1e-5),
                    tostring(0 / 0),
                    tostring(1 / 0),
                    tostring(-1 / 0),
                    tostring(numeric)
                """.trimIndent(),
                "tostring-number-format.lua",
            ),
        )
        assertEquals(LuaStatus.OK, state.pcall(0, -1), state.toString(-1))

        assertEquals("1", state.toString(1))
        assertEquals("1.0", state.toString(2))
        assertEquals("1.25", state.toString(3))
        assertEquals("100000000000000.0", state.toString(4))
        assertEquals("1e+15", state.toString(5))
        assertEquals("1e-05", state.toString(6))
        assertEquals("nan", state.toString(7))
        assertEquals("inf", state.toString(8))
        assertEquals("-inf", state.toString(9))
        assertEquals("1e+15", state.toString(10))
    }

    @Test
    fun `number to string uses locale decimal point like lua`() {
        val previousLocale = Locale.getDefault()
        Locale.setDefault(Locale.GERMANY)
        val path = Files.createTempFile("klua-number-locale-string-", ".txt")
        val state = LuaState.create()
        LuaStdlib.openBase(state)
        LuaStdlib.openString(state)
        LuaStdlib.openIo(state)
        LuaStdlib.openTable(state)

        try {
            assertEquals(
                LuaStatus.OK,
                state.load(
                    """
                    local handle = assert(io.open("${path.luaPath()}", "w+"))
                    handle:write(1.5, "|", 1.0)
                    handle:seek("set", 0)
                    local written = handle:read("a")
                    handle:close()
                    local gsubResult, gsubCount = ("x"):gsub("x", 1.5)
                    return tostring(1.5),
                        tostring(1.0),
                        tostring(1e15),
                        table.concat({1.5, 1.0, 1e15}, "|"),
                        gsubResult,
                        gsubCount,
                        string.format("%s|%s", 1.5, 1.0),
                        written
                    """.trimIndent(),
                    "number-locale-string.lua",
                ),
            )
            assertEquals(LuaStatus.OK, state.pcall(0, -1), state.toString(-1))

            assertEquals("1,5", state.toString(1))
            assertEquals("1,0", state.toString(2))
            assertEquals("1e+15", state.toString(3))
            assertEquals("1,5|1,0|1e+15", state.toString(4))
            assertEquals("1,5", state.toString(5))
            assertEquals(1L, state.toInteger(6))
            assertEquals("1,5|1,0", state.toString(7))
            assertEquals("1,5|1,0", state.toString(8))
        } finally {
            Locale.setDefault(previousLocale)
            Files.deleteIfExists(path)
        }
    }

    @Test
    fun `tostring reports table and function identities`() {
        val state = LuaState.create()
        LuaStdlib.openBase(state)
        LuaStdlib.openString(state)

        assertEquals(
            LuaStatus.OK,
            state.load(
                """
                local tableText = tostring({})
                local functionText = tostring(function() end)
                return tableText, functionText
                """.trimIndent(),
                "tostring-identities.lua",
            ),
        )
        assertEquals(LuaStatus.OK, state.pcall(0, -1), state.toString(-1))

        assertTrue(state.toString(1)?.matches(Regex("""table: [0-9a-f]+""")) == true)
        assertTrue(state.toString(2)?.matches(Regex("""function: [0-9a-f]+""")) == true)
    }

