    @Test
    fun `openLibs installs package table`() {
        val state = LuaState.create(LuaConfig(packagePathEnvironmentEnabled = false))
        LuaStdlib.openLibs(state)

        assertEquals(
            LuaStatus.OK,
            state.load(
                """
                return type(package), type(package.searchpath), package.path, package.config,
                    type(package.loaded), type(package.preload), type(package.searchers), type(require),
                    type(package.loadlib), package.cpath,
                    type(package.searchers[1]), type(package.searchers[2]),
                    type(package.searchers[3]), type(package.searchers[4])
                """.trimIndent(),
                "package-openlibs.lua",
            ),
        )
        assertEquals(LuaStatus.OK, state.pcall(0, -1))

        assertEquals("table", state.toString(1))
        assertEquals("function", state.toString(2))
        assertEquals(
            LuaPackageLibrary.resolvePackagePath(
                "LUA_PATH",
                LuaPackageLibrary.defaultLuaPath,
                environmentEnabled = false,
            ),
            state.toString(3),
        )
        assertEquals("${File.separator}\n;\n?\n!\n-\n", state.toString(4))
        assertEquals("table", state.toString(5))
        assertEquals("table", state.toString(6))
        assertEquals("table", state.toString(7))
        assertEquals("function", state.toString(8))
        assertEquals("function", state.toString(9))
        assertEquals(
            LuaPackageLibrary.resolvePackagePath(
                "LUA_CPATH",
                LuaPackageLibrary.defaultCPath,
                environmentEnabled = false,
            ),
            state.toString(10),
        )
        assertEquals("function", state.toString(11))
        assertEquals("function", state.toString(12))
        assertEquals("function", state.toString(13))
        assertEquals("function", state.toString(14))
    }

    @Test
    fun `package path initialization follows versioned environment and default insertion rules`() {
        val defaultPath = "default-a;default-b"

        fun resolve(
            environment: Map<String, String>,
            enabled: Boolean = true,
            executableDirectory: String? = "C:\\runtime",
        ): String = LuaPackageLibrary.resolvePackagePath(
            environmentName = "LUA_PATH",
            defaultPath = defaultPath,
            environmentEnabled = enabled,
            environment = environment::get,
            executableDirectory = executableDirectory,
        )

        assertEquals(
            "versioned",
            resolve(mapOf("LUA_PATH_5_5" to "versioned", "LUA_PATH" to "unversioned")),
        )
        assertEquals("unversioned", resolve(mapOf("LUA_PATH" to "unversioned")))
        assertEquals("", resolve(mapOf("LUA_PATH_5_5" to "", "LUA_PATH" to "unversioned")))
        assertEquals(defaultPath, resolve(mapOf("LUA_PATH_5_5" to "versioned"), enabled = false))
        assertEquals("head;$defaultPath;tail;;last", resolve(mapOf("LUA_PATH_5_5" to "head;;tail;;last")))
        assertEquals("$defaultPath;tail", resolve(mapOf("LUA_PATH_5_5" to ";;tail")))
        assertEquals("head;$defaultPath", resolve(mapOf("LUA_PATH_5_5" to "head;;")))

        val executablePath = resolve(mapOf("LUA_PATH_5_5" to "before!after"))
        if (File.separatorChar == '\\') {
            assertEquals("beforeC:\\runtimeafter", executablePath)
            assertFailsWith<LuaRuntimeException> {
                resolve(mapOf("LUA_PATH_5_5" to "!\\?.lua"), executableDirectory = null)
            }
        } else {
            assertEquals("before!after", executablePath)
        }
    }

    @Test
    fun `openLibs installs minimal debug library`() {
        val state = LuaState.create()
        LuaStdlib.openLibs(state)
        val debugOutput = mutableListOf<String>()
        LuaStdlib.openDebug(state, LuaDebugInput { null }, Consumer(debugOutput::add))

        assertEquals(
            LuaStatus.OK,
            state.load(
                """
                local info = debug.getinfo(1)
                return type(debug), type(debug.traceback), type(debug.getinfo), type(debug.getlocal),
                    type(debug.setlocal), type(debug.getupvalue), type(debug.setupvalue),
                    type(debug.upvalueid), type(debug.upvaluejoin), type(debug.getuservalue),
                    type(debug.setuservalue), type(debug.getmetatable), type(debug.setmetatable), type(debug.getregistry),
                    type(debug.sethook), type(debug.gethook), debug.traceback("boom"),
                    type(info), info.what, info.source, info.currentline,
                    type(debug.debug), pcall(debug.debug)
                """.trimIndent(),
                "debug-openlibs.lua",
            ),
        )
        assertEquals(LuaStatus.OK, state.pcall(0, -1), state.toString(-1))

        assertEquals("table", state.toString(1))
        assertEquals("function", state.toString(2))
        assertEquals("function", state.toString(3))
        assertEquals("function", state.toString(4))
        assertEquals("function", state.toString(5))
        assertEquals("function", state.toString(6))
        assertEquals("function", state.toString(7))
        assertEquals("function", state.toString(8))
        assertEquals("function", state.toString(9))
        assertEquals("function", state.toString(10))
        assertEquals("function", state.toString(11))
        assertEquals("function", state.toString(12))
        assertEquals("function", state.toString(13))
        assertEquals("function", state.toString(14))
        assertEquals("function", state.toString(15))
        assertEquals("function", state.toString(16))
        assertTrue(state.toString(17)?.contains("boom\nstack traceback:") == true)
        assertEquals("table", state.toString(18))
        assertEquals("main", state.toString(19))
        assertEquals("debug-openlibs.lua", state.toString(20))
        assertEquals(1L, state.toInteger(21))
        assertEquals("function", state.toString(22))
        assertTrue(state.toBoolean(23))
        assertEquals(listOf("lua_debug> "), debugOutput)
    }

    @Test
    fun `debug debug runs protected command lines until cont`() {
        val state = LuaState.create()
        LuaStdlib.openLibs(state, Consumer { })
        val commands = ArrayDeque(
            listOf(
                "debugCounter = (debugCounter or 0) + 1",
                "debugCallerSource = debug.getinfo(2, \"S\").source",
                "return 1, 2, 3",
                "error(\"runtime boom\", 0)",
                "local =",
                "debugCounter = debugCounter + 1",
                "cont",
            ),
        )
        val output = mutableListOf<String>()
        LuaStdlib.openDebug(
            state,
            LuaDebugInput { commands.removeFirstOrNull() },
            Consumer(output::add),
        )

        assertEquals(
            LuaStatus.OK,
            state.load(
                """
                local results = table.pack(debug.debug("ignored", {}, 3))
                return debugCounter, results.n, debugCallerSource
                """.trimIndent(),
                "debug-command-loop.lua",
            ),
        )
        assertEquals(LuaStatus.OK, state.pcall(0, -1), state.toString(-1))

        assertEquals(2L, state.toInteger(1))
        assertEquals(0L, state.toInteger(2))
        assertEquals("debug-command-loop.lua", state.toString(3))
        assertEquals(7, output.count { fragment -> fragment == "lua_debug> " })
        assertEquals(1, output.count { fragment -> "runtime boom" in fragment })
        assertEquals(1, output.count { fragment -> "debug command" in fragment })
        assertTrue(output.filterNot { fragment -> fragment == "lua_debug> " }.all { fragment -> fragment.endsWith('\n') })
    }

    @Test
    fun `debug debug stops at eof and reopened functions use updated adapters`() {
        val state = LuaState.create()
        LuaStdlib.openLibs(state, Consumer { })
        val firstCommands = ArrayDeque(listOf("debugReopen = 1"))
        val firstOutput = mutableListOf<String>()
        LuaStdlib.openDebug(
            state,
            LuaDebugInput { firstCommands.removeFirstOrNull() },
            Consumer(firstOutput::add),
        )

        assertEquals(
            LuaStatus.OK,
            state.load(
                """
                savedDebug = debug.debug
                local results = table.pack(savedDebug())
                return debugReopen, results.n
                """.trimIndent(),
                "debug-command-eof.lua",
            ),
        )
        assertEquals(LuaStatus.OK, state.pcall(0, -1), state.toString(-1))
        assertEquals(1L, state.toInteger(1))
        assertEquals(0L, state.toInteger(2))
        assertEquals(listOf("lua_debug> ", "lua_debug> "), firstOutput)

        state.setTop(0)
        val secondCommands = ArrayDeque(listOf("debugReopen = debugReopen + 1", "cont"))
        val secondOutput = mutableListOf<String>()
        LuaStdlib.openDebug(
            state,
            LuaDebugInput { secondCommands.removeFirstOrNull() },
            Consumer(secondOutput::add),
        )
        assertEquals(
            LuaStatus.OK,
            state.load(
                """
                local same = savedDebug == debug.debug
                local results = table.pack(savedDebug("ignored"))
                return same, debugReopen, results.n
                """.trimIndent(),
                "debug-command-reopen.lua",
            ),
        )
        assertEquals(LuaStatus.OK, state.pcall(0, -1), state.toString(-1))
        assertTrue(state.toBoolean(1))
        assertEquals(2L, state.toInteger(2))
        assertEquals(0L, state.toInteger(3))
        assertEquals(listOf("lua_debug> ", "lua_debug> "), secondOutput)
    }

    @Test
    fun `debug debug rejects yielded commands and continues with a clean stack`() {
        val state = LuaState.create()
        LuaStdlib.openLibs(state, Consumer { })
        val commands = ArrayDeque(
            listOf(
                "coroutine.yield(\"forbidden\")",
                "debugAfterYield = true",
                "cont",
            ),
        )
        val output = mutableListOf<String>()
        LuaStdlib.openDebug(
            state,
            LuaDebugInput { commands.removeFirstOrNull() },
            Consumer(output::add),
        )

        assertEquals(
            LuaStatus.OK,
            state.load(
                """
                local co = coroutine.create(function()
                    debug.debug()
                    return "done"
                end)
                local ok, result = coroutine.resume(co)
                return ok, result, debugAfterYield, coroutine.status(co)
                """.trimIndent(),
                "debug-command-yield.lua",
            ),
        )
        assertEquals(LuaStatus.OK, state.pcall(0, -1), state.toString(-1))

        assertTrue(state.toBoolean(1))
        assertEquals("done", state.toString(2))
        assertTrue(state.toBoolean(3))
        assertEquals("dead", state.toString(4))
        assertEquals(3, output.count { fragment -> fragment == "lua_debug> " })
        assertEquals(1, output.count { fragment -> "attempt to yield across a C-call boundary" in fragment })
    }

    @Test
    fun `default debug command adapters use stdin and stderr`() {
        val previousInput = System.`in`
        val previousError = System.err
        val errorBytes = ByteArrayOutputStream()
        try {
            System.setIn(ByteArrayInputStream("defaultDebugValue = 9\ncont\n".toByteArray(StandardCharsets.UTF_8)))
            System.setErr(PrintStream(errorBytes, true, StandardCharsets.UTF_8))
            val state = LuaState.create()
            LuaStdlib.openBase(state, Consumer { })
            LuaStdlib.openDebug(state)

            assertEquals(
                LuaStatus.OK,
                state.load("debug.debug(); return defaultDebugValue", "debug-default-adapters.lua"),
            )
            assertEquals(LuaStatus.OK, state.pcall(0, -1), state.toString(-1))
            assertEquals(9L, state.toInteger(1))
            assertEquals("lua_debug> lua_debug> ", errorBytes.toString(StandardCharsets.UTF_8))
        } finally {
            System.setIn(previousInput)
            System.setErr(previousError)
        }
    }

