        assertEquals("line", state.toString(4))
        assertEquals("number", state.toString(5))
        assertTrue((state.toInteger(6) ?: 0L) >= 2L)
        assertEquals(3L, state.toInteger(7))
    }

    @Test
    fun `io file handles write read seek and close`() {
        val path = Files.createTempFile("klua-io-test-", ".txt")
        Files.deleteIfExists(path)
        val state = LuaState.create()
        LuaStdlib.openBase(state)
        LuaStdlib.openIo(state)

        try {
            assertEquals(
                LuaStatus.OK,
                state.load(
                    """
                    local handle = assert(io.open("${path.luaPath()}", "w+"))
                    local before = io.type(handle)
                    local written = handle:write("alpha\n\nbeta")
                    local position = handle:seek("set", 0)
                    local line = handle:read("l")
                    local blank = handle:read("l")
                    local rest = handle:read("a")
                    local closed = handle:close()
                    local after = io.type(handle)
                    local secondCloseOk, secondMessage = pcall(function()
                        return handle:close()
                    end)
                    return before, written == handle, position, line, blank, rest, closed,
                        after, secondCloseOk, secondMessage
                    """.trimIndent(),
                    "io-file-handle.lua",
                ),
            )
            assertEquals(LuaStatus.OK, state.pcall(0, -1), state.toString(-1))

            assertEquals("file", state.toString(1))
            assertTrue(state.toBoolean(2))
            assertEquals(0L, state.toInteger(3))
            assertEquals("alpha", state.toString(4))
            assertEquals("", state.toString(5))
            assertEquals("beta", state.toString(6))
            assertTrue(state.toBoolean(7))
            assertEquals("closed file", state.toString(8))
            assertFalse(state.toBoolean(9))
            assertEquals("attempt to use a closed file", state.toString(10))
        } finally {
            Files.deleteIfExists(path)
        }
    }

    @Test
    fun `io file handles format tostring like lua`() {
        val path = Files.createTempFile("klua-io-tostring-", ".txt")
        val state = LuaState.create()
        LuaStdlib.openLibs(state)

        try {
            assertEquals(
                LuaStatus.OK,
                state.load(
                    """
                    local openHandle = assert(io.open("${path.luaPath()}", "w"))
                    local openText = tostring(openHandle)
                    openHandle:close()

                    local handle = assert(io.open("${path.luaPath()}", "r"))
                    handle:close()
                    debug.setmetatable(handle, { __name = "NamedFile" })
                    local namedText = tostring(handle)
                    debug.setmetatable(handle, {
                        __tostring = function()
                            return "custom-file"
                        end,
                    })
                    local customText = tostring(handle)
                    debug.setmetatable(handle, nil)
                    local clearedText = tostring(handle)
                    local defaultClosed = assert(io.open("${path.luaPath()}", "r"))
                    defaultClosed:close()
                    return openText, namedText, customText, clearedText, tostring(handle), tostring(defaultClosed)
                    """.trimIndent(),
                    "io-file-tostring.lua",
                ),
            )
            assertEquals(LuaStatus.OK, state.pcall(0, -1), state.toString(-1))

            assertTrue(state.toString(1)?.matches(Regex("""file \([0-9a-f]+\)""")) == true, state.toString(1))
            assertTrue(state.toString(2)?.matches(Regex("""NamedFile: [0-9a-f]+""")) == true, state.toString(2))
            assertEquals("custom-file", state.toString(3))
            assertTrue(state.toString(4)?.matches(Regex("""userdata: [0-9a-f]+""")) == true, state.toString(4))
            assertTrue(state.toString(5)?.matches(Regex("""userdata: [0-9a-f]+""")) == true, state.toString(5))
            assertEquals("file (closed)", state.toString(6))
        } finally {
            Files.deleteIfExists(path)
        }
    }

    @Test
    fun `io module rejects handles without file metatable`() {
        val path = Files.createTempFile("klua-io-metatable-", ".txt")
        Files.writeString(path, "seed")
        val state = LuaState.create()
        LuaStdlib.openLibs(state)

        try {
            assertEquals(
                LuaStatus.OK,
                state.load(
                    """
                    local typed = assert(io.open("${path.luaPath()}", "r"))
                    local openType = io.type(typed)
                    typed:close()
                    local closedType = io.type(typed)
                    debug.setmetatable(typed, nil)
                    local clearedType = io.type(typed)

                    local closeHandle = assert(io.open("${path.luaPath()}", "r"))
                    closeHandle:close()
                    debug.setmetatable(closeHandle, nil)
                    local closeOk, closeMessage = pcall(io.close, closeHandle)

                    local inputHandle = assert(io.open("${path.luaPath()}", "r"))
                    inputHandle:close()
                    debug.setmetatable(inputHandle, {})
                    local inputOk, inputMessage = pcall(io.input, inputHandle)

                    local outputHandle = assert(io.open("${path.luaPath()}", "w"))
                    outputHandle:close()
                    debug.setmetatable(outputHandle, {})
                    local outputOk, outputMessage = pcall(io.output, outputHandle)

                    return openType, closedType, clearedType,
                        closeOk, closeMessage,
                        inputOk, inputMessage,
                        outputOk, outputMessage
                    """.trimIndent(),
                    "io-file-metatable.lua",
                ),
            )
            assertEquals(LuaStatus.OK, state.pcall(0, -1), state.toString(-1))

            assertEquals("file", state.toString(1))
            assertEquals("closed file", state.toString(2))
            assertTrue(state.isNil(3))
            assertFalse(state.toBoolean(4))
            assertEquals("bad argument #1 to 'io.close' (FILE* expected)", state.toString(5))
            assertFalse(state.toBoolean(6))
            assertEquals("bad argument #1 to 'io.input' (FILE* expected)", state.toString(7))
            assertFalse(state.toBoolean(8))
            assertEquals("bad argument #1 to 'io.output' (FILE* expected)", state.toString(9))
        } finally {
            Files.deleteIfExists(path)
        }
    }

