    fun `io write converts arguments incrementally and reports failure byte counts`() {
        val path = Files.createTempFile("klua-io-write-order-", ".txt")
        val partialPath = Files.createTempFile("klua-io-write-partial-", ".txt")
        Files.writeString(path, "seed")
        val state = LuaState.create()
        LuaStdlib.openBase(state)
        LuaStdlib.openIo(state)

        try {
            assertEquals(
                LuaStatus.OK,
                state.load(
                    """
                    local readOnly = assert(io.open("${path.luaPath()}", "r"))
                    local emptyReturned = readOnly:write() == readOnly
                    local invalidOk, invalidMessage = pcall(readOnly.write, readOnly, {})
                    local directionCount = select("#", readOnly:write("x", {}))
                    local directionValue, directionMessage, directionCode, directionBytes =
                        readOnly:write("x", {})

                    io.output(readOnly)
                    local moduleEmptyReturned = io.write() == readOnly
                    local moduleInvalidOk, moduleInvalidMessage = pcall(io.write, {})
                    local moduleValue, moduleMessage, moduleCode, moduleBytes = io.write("x", {})
                    readOnly:close()

                    local partial = assert(io.open("${partialPath.luaPath()}", "w+"))
                    local laterOk, laterMessage = pcall(partial.write, partial, "prefix", {})
                    partial:seek("set", 0)
                    local partialText = partial:read("a")
                    partial:close()

                    local closedDefault = assert(io.open("${partialPath.luaPath()}", "w"))
                    io.output(closedDefault)
                    closedDefault:close()
                    local closedOk, closedMessage = pcall(io.write, {})

                    return emptyReturned, invalidOk, invalidMessage,
                        directionCount, directionValue, directionMessage,
                        type(directionCode), directionBytes,
                        moduleEmptyReturned, moduleInvalidOk, moduleInvalidMessage,
                        moduleValue, moduleMessage, type(moduleCode), moduleBytes,
                        laterOk, laterMessage, partialText,
                        closedOk, closedMessage
                    """.trimIndent(),
                    "io-write-order.lua",
                ),
            )
            assertEquals(LuaStatus.OK, state.pcall(0, -1), state.toString(-1))

            assertTrue(state.toBoolean(1))
            assertFalse(state.toBoolean(2))
            assertEquals("bad argument #2 to 'write' (string expected)", state.toString(3))
            assertEquals(4L, state.toInteger(4))
            assertTrue(state.isNil(5))
            assertEquals("Bad file descriptor", state.toString(6))
            assertEquals("number", state.toString(7))
            assertEquals(0L, state.toInteger(8))
            assertTrue(state.toBoolean(9))
            assertFalse(state.toBoolean(10))
            assertEquals("bad argument #1 to 'write' (string expected)", state.toString(11))
            assertTrue(state.isNil(12))
            assertEquals("Bad file descriptor", state.toString(13))
            assertEquals("number", state.toString(14))
            assertEquals(0L, state.toInteger(15))
            assertFalse(state.toBoolean(16))
            assertEquals("bad argument #3 to 'write' (string expected)", state.toString(17))
            assertEquals("prefix", state.toString(18))
            assertFalse(state.toBoolean(19))
            assertEquals("default output file is closed", state.toString(20))
        } finally {
            Files.deleteIfExists(path)
            Files.deleteIfExists(partialPath)
        }
    }

    @Test
    fun `io write counts bytes accepted by failing stream arguments`() {
        val zeroSink = ByteLimitOutputStream(0)
        val partialSink = ByteLimitOutputStream(7)
        val fullSink = ByteLimitOutputStream(Int.MAX_VALUE)
        val state = LuaState.create()
        LuaStdlib.openBase(state)
        LuaStdlib.openIo(state)
        LuaIoLibrary.pushOutputHandle(state, zeroSink)
        state.setGlobal("zeroSink")
        LuaIoLibrary.pushOutputHandle(state, partialSink)
        state.setGlobal("partialSink")
        LuaIoLibrary.pushOutputHandle(state, fullSink)
        state.setGlobal("fullSink")

        assertEquals(
            LuaStatus.OK,
            state.load(
                """
                local function pack(...)
                    return select("#", ...), ...
                end

                local zeroCount, zeroValue, zeroMessage, zeroCode, zeroBytes =
                    pack(zeroSink:write("x"))

                io.output(partialSink)
                local partialCount, partialValue, partialMessage, partialCode, partialBytes =
                    pack(io.write("abc", "\0de", 42, "tail"))
                local flushCount, flushValue, flushMessage, flushCode = pack(partialSink:flush())
                local closeCount, closeValue, closeMessage, closeCode = pack(partialSink:close())

                local emptyReturned = fullSink:write() == fullSink
                local fullReturned = fullSink:write("", 1.5, "ok") == fullSink
                local fullFlush = fullSink:flush()
                local fullClose = fullSink:close()

                return zeroCount, zeroValue, zeroMessage, zeroCode, zeroBytes,
                    partialCount, partialValue, partialMessage, partialCode, partialBytes,
                    flushCount, flushValue, flushMessage, flushCode,
                    closeCount, closeValue, closeMessage, closeCode, io.type(partialSink),
                    emptyReturned, fullReturned, fullFlush, fullClose
                """.trimIndent(),
                "io-write-partial-stream.lua",
            ),
        )
        assertEquals(LuaStatus.OK, state.pcall(0, -1), state.toString(-1))

        assertEquals(4L, state.toInteger(1))
        assertTrue(state.isNil(2))
        assertEquals("forced write failure", state.toString(3))
        assertEquals(1L, state.toInteger(4))
        assertEquals(0L, state.toInteger(5))
        assertEquals(4L, state.toInteger(6))
        assertTrue(state.isNil(7))
        assertEquals("forced write failure", state.toString(8))
        assertEquals(1L, state.toInteger(9))
        assertEquals(7L, state.toInteger(10))
        assertEquals(3L, state.toInteger(11))
        assertTrue(state.isNil(12))
        assertEquals("forced write failure", state.toString(13))
        assertEquals(1L, state.toInteger(14))
        assertEquals(3L, state.toInteger(15))
        assertTrue(state.isNil(16))
        assertEquals("forced write failure", state.toString(17))
        assertEquals(1L, state.toInteger(18))
        assertEquals("closed file", state.toString(19))
        (20..23).forEach { index -> assertTrue(state.toBoolean(index)) }

        assertEquals(emptyList(), zeroSink.acceptedBytes.toList())
        assertEquals(
            listOf('a'.code, 'b'.code, 'c'.code, 0, 'd'.code, 'e'.code, '4'.code),
            partialSink.acceptedBytes.map { byte -> byte.toInt() and 0xff },
        )
        assertEquals("1.5ok", fullSink.acceptedBytes.toString(StandardCharsets.ISO_8859_1))
    }

    @Test
    fun `io buffered writes attribute drain failures to current arguments`() {
        val fullSink = ByteLimitOutputStream(5)
        val linePrefixSink = ByteLimitOutputStream(3)
        val lineSuffixSink = ByteLimitOutputStream(3)
        val state = LuaState.create()
        LuaStdlib.openBase(state)
        LuaStdlib.openIo(state)
        LuaIoLibrary.pushOutputHandle(state, fullSink)
        state.setGlobal("fullFailure")
        LuaIoLibrary.pushOutputHandle(state, linePrefixSink)
        state.setGlobal("linePrefixFailure")
        LuaIoLibrary.pushOutputHandle(state, lineSuffixSink)
        state.setGlobal("lineSuffixFailure")

        assertEquals(
            LuaStatus.OK,
            state.load(
                """
                local function pack(...)
                    return select("#", ...), ...
                end

                assert(fullFailure:setvbuf("full", 6))
                local fullFirst = fullFailure:write("abc") == fullFailure
                local fullCount, fullValue, fullMessage, fullCode, fullBytes =
                    pack(fullFailure:write("defg"))

                assert(linePrefixFailure:setvbuf("line", 64))
                local linePrefixFirst = linePrefixFailure:write("ab") == linePrefixFailure
                local prefixCount, prefixValue, prefixMessage, prefixCode, prefixBytes =
                    pack(linePrefixFailure:write("c\ndef"))

                assert(lineSuffixFailure:setvbuf("line", 2))
                local suffixCount, suffixValue, suffixMessage, suffixCode, suffixBytes =
                    pack(lineSuffixFailure:write("a\nbc"))

                return fullFirst, fullCount, fullValue, fullMessage, fullCode, fullBytes,
                    linePrefixFirst, prefixCount, prefixValue, prefixMessage, prefixCode, prefixBytes,
                    suffixCount, suffixValue, suffixMessage, suffixCode, suffixBytes
                """.trimIndent(),
                "io-write-buffered-partial-stream.lua",
            ),
        )
        assertEquals(LuaStatus.OK, state.pcall(0, -1), state.toString(-1))

        assertTrue(state.toBoolean(1))
        assertEquals(4L, state.toInteger(2))
        assertTrue(state.isNil(3))
        assertEquals("forced write failure", state.toString(4))
        assertEquals(1L, state.toInteger(5))
        assertEquals(2L, state.toInteger(6))
        assertTrue(state.toBoolean(7))
        assertEquals(4L, state.toInteger(8))
        assertTrue(state.isNil(9))
        assertEquals("forced write failure", state.toString(10))
        assertEquals(1L, state.toInteger(11))
        assertEquals(1L, state.toInteger(12))
        assertEquals(4L, state.toInteger(13))
        assertTrue(state.isNil(14))
        assertEquals("forced write failure", state.toString(15))
        assertEquals(1L, state.toInteger(16))
        assertEquals(3L, state.toInteger(17))

        assertEquals("abcde", fullSink.acceptedBytes.toString(StandardCharsets.ISO_8859_1))
        assertEquals("abc", linePrefixSink.acceptedBytes.toString(StandardCharsets.ISO_8859_1))
        assertEquals("a\nb", lineSuffixSink.acceptedBytes.toString(StandardCharsets.ISO_8859_1))
    }

    @Test
    fun `io close finalizes owned handles after drain and close failures`() {
        val combinedSink = ByteLimitOutputStream(1)
        val closeOnlySink = ByteLimitOutputStream(Int.MAX_VALUE, alwaysFailClose = true)
        val metamethodSink = ByteLimitOutputStream(0)
        val state = LuaState.create()
        LuaStdlib.openBase(state)
        LuaStdlib.openIo(state)
        LuaIoLibrary.pushOutputHandle(state, combinedSink)
        state.setGlobal("combinedFailure")
        LuaIoLibrary.pushOutputHandle(state, closeOnlySink)
        state.setGlobal("closeOnlyFailure")
        LuaIoLibrary.pushOutputHandle(state, metamethodSink)
        state.setGlobal("metamethodFailure")

        assertEquals(
            LuaStatus.OK,
            state.load(
                """
                local function pack(...)
                    return select("#", ...), ...
                end

                assert(combinedFailure:setvbuf("full", 10))
                assert(combinedFailure:write("abc") == combinedFailure)
                io.output(combinedFailure)
                local closeCount, closeValue, closeMessage, closeCode = pack(combinedFailure:close())
                local combinedType = io.type(combinedFailure)
                local repeatOk, repeatMessage = pcall(combinedFailure.close, combinedFailure)
                local useOk, useMessage = pcall(combinedFailure.write, combinedFailure, "x")
                local defaultOk, defaultMessage = pcall(io.write, "x")

                assert(closeOnlyFailure:write("ok") == closeOnlyFailure)
                local closeOnlyCount, closeOnlyValue, closeOnlyMessage, closeOnlyCode =
                    pack(closeOnlyFailure:close())

                local automatic
                do
                    local handle <close> = metamethodFailure
                    assert(handle:setvbuf("full", 10))
                    local buffered = handle:write("meta") == handle
                    automatic = handle
                    assert(buffered)
                end

                return closeCount, closeValue, closeMessage, closeCode, combinedType,
                    repeatOk, repeatMessage, useOk, useMessage, defaultOk, defaultMessage,
                    closeOnlyCount, closeOnlyValue, closeOnlyMessage, closeOnlyCode,
                    io.type(closeOnlyFailure), io.type(automatic)
                """.trimIndent(),
                "io-close-finalization-failures.lua",
            ),
        )
        assertEquals(LuaStatus.OK, state.pcall(0, -1), state.toString(-1))

        assertEquals(3L, state.toInteger(1))
        assertTrue(state.isNil(2))
        assertEquals("forced write failure", state.toString(3))
        assertEquals(1L, state.toInteger(4))
        assertEquals("closed file", state.toString(5))
        assertFalse(state.toBoolean(6))
        assertEquals("attempt to use a closed file", state.toString(7))
        assertFalse(state.toBoolean(8))
        assertEquals("attempt to use a closed file", state.toString(9))
        assertFalse(state.toBoolean(10))
        assertEquals("default output file is closed", state.toString(11))
        assertEquals(3L, state.toInteger(12))
        assertTrue(state.isNil(13))
        assertEquals("forced close failure", state.toString(14))
        assertEquals(1L, state.toInteger(15))
        assertEquals("closed file", state.toString(16))
        assertEquals("closed file", state.toString(17))

        assertEquals("a", combinedSink.acceptedBytes.toString(StandardCharsets.ISO_8859_1))
        assertEquals(1, combinedSink.closeAttempts)
        assertEquals("ok", closeOnlySink.acceptedBytes.toString(StandardCharsets.ISO_8859_1))
        assertEquals(1, closeOnlySink.closeAttempts)
        assertEquals(1, metamethodSink.closeAttempts)
    }

    @Test
    fun `io tmpfile returns closeable file handles`() {
        val temporaryDirectory = Path.of(System.getProperty("java.io.tmpdir"))
        fun temporaryIoFiles(): Set<Path> = Files.list(temporaryDirectory).use { paths ->
            paths.iterator().asSequence()
                .filter { path ->
                    val name = path.fileName.toString()
                    name.startsWith("klua-io-") && name.endsWith(".tmp")
                }
                .toSet()
        }
        val beforeTemporaryFiles = temporaryIoFiles()
        val state = LuaState.create()
        LuaStdlib.openBase(state)
        LuaStdlib.openIo(state)

        assertEquals(
            LuaStatus.OK,
            state.load(
                """
                local resultCount, handle = (function(...)
                    return select("#", ...), ...
                end)(io.tmpfile({}, "ignored"))
                assert(handle)
                local before = io.type(handle)
                handle:write("scratch")
                handle:seek("set", 0)
                local data = handle:read("*a")
                local closed = io.close(handle, {}, "ignored")
                local after = io.type(handle, {}, "ignored")
                local nonFile = io.type({}, "ignored")
                local readOk, readMessage = pcall(function()
                    return handle:read()
                end)
                local missingOk, missingMessage = pcall(io.type)
                return resultCount, before, data, closed, after, nonFile, readOk, readMessage,
                    missingOk, missingMessage
                """.trimIndent(),
                "io-tmpfile.lua",
            ),
        )
        assertEquals(LuaStatus.OK, state.pcall(0, -1), state.toString(-1))

        assertEquals(1L, state.toInteger(1))
        assertEquals("file", state.toString(2))
        assertEquals("scratch", state.toString(3))
        assertTrue(state.toBoolean(4))
        assertEquals("closed file", state.toString(5))
        assertTrue(state.isNil(6))
        assertFalse(state.toBoolean(7))
        assertEquals("attempt to use a closed file", state.toString(8))
        assertFalse(state.toBoolean(9))
        assertEquals("bad argument #1 to 'type' (value expected)", state.toString(10))
        assertEquals(beforeTemporaryFiles, temporaryIoFiles())
    }

    @Test
    fun `io lines iterates file handles and named files`() {
        val path = Files.createTempFile("klua-io-lines-", ".txt")
        Files.writeString(path, "one\n\ntwo\n")
        val state = LuaState.create()
        LuaStdlib.openBase(state)
        LuaStdlib.openIo(state)

        try {
            assertEquals(
                LuaStatus.OK,
                state.load(
                    """
                    local handle = assert(io.open("${path.luaPath()}", "r"))
                    local fromHandle = {}
                    for line in handle:lines() do
                        fromHandle[#fromHandle + 1] = line
                    end
                    local stillOpen = io.type(handle)
                    handle:close()

                    local iterator, stateValue, control, closeFile = io.lines("${path.luaPath()}")
                    local first = iterator(stateValue, control)
                    local second = iterator(stateValue, first)
                    local third = iterator(stateValue, second)
                    local done = iterator(stateValue, third)
                    local closed = io.type(closeFile)
                    local closedIteratorOk, closedIteratorMessage = pcall(iterator, stateValue, third)
                    return fromHandle[1], fromHandle[2], fromHandle[3], fromHandle[4],
                        stillOpen, first, second, third, done, closed, closedIteratorOk, closedIteratorMessage
                    """.trimIndent(),
                    "io-lines.lua",
                ),
            )
            assertEquals(LuaStatus.OK, state.pcall(0, -1), state.toString(-1))

            assertEquals("one", state.toString(1))
            assertEquals("", state.toString(2))
            assertEquals("two", state.toString(3))
            assertTrue(state.isNil(4))
            assertEquals("file", state.toString(5))
            assertEquals("one", state.toString(6))
            assertEquals("", state.toString(7))
            assertEquals("two", state.toString(8))
            assertTrue(state.isNil(9))
            assertEquals("closed file", state.toString(10))
            assertFalse(state.toBoolean(11))
            assertEquals("file is already closed", state.toString(12))
        } finally {
            Files.deleteIfExists(path)
        }
    }

    @Test
    fun `io lines preserves constructor and iterator result shapes`() {
        val path = Files.createTempFile("klua-io-lines-shapes-", ".txt")
        val emptyPath = Files.createTempFile("klua-io-lines-empty-", ".txt")
        Files.writeString(path, "one\ntwo\n")
        val state = LuaState.create()
        LuaStdlib.openBase(state)
        LuaStdlib.openIo(state)

        try {
            assertEquals(
                LuaStatus.OK,
                state.load(
                    """
                    local function capture(...)
                        return select("#", ...), ...
                    end

                    local namedCount, iterator, iteratorState, control, closeFile =
                        capture(io.lines("${path.luaPath()}", "l", "L"))
                    local firstCount, first, second = capture(iterator(iteratorState, control))
                    local doneCount = select("#", iterator(iteratorState, first))
                    local namedClosed = io.type(closeFile)
                    local repeatedOk, repeatedMessage = pcall(iterator, iteratorState, first)

                    local owned = assert(io.open("${path.luaPath()}", "r"))
                    local ownedConstructorCount, ownedIterator = capture(owned:lines("l", "L"))
                    local ownedFirstCount, ownedFirst, ownedSecond = capture(ownedIterator())
                    local ownedDoneCount = select("#", ownedIterator())
                    local ownedAfter = io.type(owned)
                    owned:close()

                    local default = io.input("${path.luaPath()}")
                    local defaultConstructorCount, defaultIterator = capture(io.lines(nil, "l", "L"))
                    local defaultFirstCount, defaultFirst, defaultSecond = capture(defaultIterator())
                    local defaultAfter = io.type(default)
                    default:close()

                    local allIterator, allState, allControl, allClose =
                        io.lines("${path.luaPath()}", "a")
                    local allFirst = allIterator(allState, allControl)
                    local allSecond = allIterator(allState, allControl)
                    local allAfter = io.type(allClose)
                    allClose:close()

                    local zeroIterator, zeroState, zeroControl, zeroClose =
                        io.lines("${emptyPath.luaPath()}", 0)
                    local zeroCount = select("#", zeroIterator(zeroState, zeroControl))
                    local zeroAfter = io.type(zeroClose)

                    return namedCount, firstCount, first, second, doneCount, namedClosed,
                        repeatedOk, repeatedMessage,
                        ownedConstructorCount, ownedFirstCount, ownedFirst, ownedSecond,
                        ownedDoneCount, ownedAfter,
                        defaultConstructorCount, defaultFirstCount, defaultFirst, defaultSecond,
                        defaultAfter, allFirst, allSecond, allAfter, zeroCount, zeroAfter
                    """.trimIndent(),
                    "io-lines-result-shapes.lua",
                ),
            )
            assertEquals(LuaStatus.OK, state.pcall(0, -1), state.toString(-1))

            assertEquals(4L, state.toInteger(1))
            assertEquals(2L, state.toInteger(2))
            assertEquals("one", state.toString(3))
            assertEquals("two\n", state.toString(4))
            assertEquals(0L, state.toInteger(5))
            assertEquals("closed file", state.toString(6))
            assertFalse(state.toBoolean(7))
            assertEquals("file is already closed", state.toString(8))
            assertEquals(1L, state.toInteger(9))
            assertEquals(2L, state.toInteger(10))
            assertEquals("one", state.toString(11))
            assertEquals("two\n", state.toString(12))
            assertEquals(0L, state.toInteger(13))
            assertEquals("file", state.toString(14))
            assertEquals(1L, state.toInteger(15))
            assertEquals(2L, state.toInteger(16))
            assertEquals("one", state.toString(17))
            assertEquals("two\n", state.toString(18))
            assertEquals("file", state.toString(19))
            assertEquals("one\ntwo\n", state.toString(20))
            assertEquals("", state.toString(21))
            assertEquals("file", state.toString(22))
            assertEquals(0L, state.toInteger(23))
            assertEquals("closed file", state.toString(24))
        } finally {
            Files.deleteIfExists(path)
            Files.deleteIfExists(emptyPath)
        }
    }

