    @Test
    fun `io lines limits source format argument count`() {
        val path = Files.createTempFile("klua-io-lines-args-", ".txt")
        Files.writeString(path, "one\n")
        val state = LuaState.create()
        LuaStdlib.openBase(state)
        LuaStdlib.openIo(state)
        LuaStdlib.openTable(state)

        try {
            assertEquals(
                LuaStatus.OK,
                state.load(
                    """
                    local args = {}
                    for index = 1, 251 do
                        args[index] = "l"
                    end
                    local handle = assert(io.open("${path.luaPath()}", "r"))
                    local handleOk, handleMessage = pcall(function()
                        return handle:lines(table.unpack(args))
                    end)
                    handle:close()
                    local moduleOk, moduleMessage = pcall(function()
                        return io.lines("${path.luaPath()}", table.unpack(args))
                    end)
                    local closedDefault = assert(io.open("${path.luaPath()}", "r"))
                    io.input(closedDefault)
                    closedDefault:close()
                    local closedOk, closedMessage = pcall(function()
                        return io.lines(nil, table.unpack(args))
                    end)
                    return handleOk, handleMessage, moduleOk, moduleMessage,
                        closedOk, closedMessage
                    """.trimIndent(),
                    "io-lines-too-many-args.lua",
                ),
            )
            assertEquals(LuaStatus.OK, state.pcall(0, -1), state.toString(-1))

            assertFalse(state.toBoolean(1))
            assertEquals("bad argument #252 to 'lines' (too many arguments)", state.toString(2))
            assertFalse(state.toBoolean(3))
            assertEquals("bad argument #252 to 'io.lines' (too many arguments)", state.toString(4))
            assertFalse(state.toBoolean(5))
            assertEquals("attempt to use a closed file", state.toString(6))
        } finally {
            Files.deleteIfExists(path)
        }
    }

    @Test
    fun `io lines named file open failures raise errors`() {
        val missingPath = Files.createTempFile("klua-io-lines-missing-", ".txt")
        Files.deleteIfExists(missingPath)
        val state = LuaState.create()
        LuaStdlib.openBase(state)
        LuaStdlib.openIo(state)

        assertEquals(
            LuaStatus.OK,
            state.load(
                """
                local opened, openMessage, openCode = io.open("${missingPath.luaPath()}", "r")
                local linesOk, linesMessage = pcall(io.lines, "${missingPath.luaPath()}")
                local inputOk, inputMessage = pcall(io.input, "${missingPath.luaPath()}")
                return opened, openMessage, type(openCode),
                    linesOk, linesMessage,
                    inputOk, inputMessage
                """.trimIndent(),
                "io-lines-open-failure.lua",
            ),
        )
        assertEquals(LuaStatus.OK, state.pcall(0, -1), state.toString(-1))

        assertTrue(state.isNil(1))
        assertTrue(
            state.toString(2)?.startsWith("$missingPath: ") == true,
            state.toString(2),
        )
        assertEquals("number", state.toString(3))
        assertFalse(state.toBoolean(4))
        assertTrue(
            state.toString(5)?.startsWith("cannot open file '$missingPath' (") == true,
            state.toString(5),
        )
        assertFalse(state.toBoolean(6))
        assertTrue(
            state.toString(7)?.startsWith("cannot open file '$missingPath' (") == true,
            state.toString(7),
        )
    }

    @Test
    fun `io lines validates read formats when iterator runs`() {
        val path = Files.createTempFile("klua-io-lines-format-", ".txt")
        Files.writeString(path, "alpha\n")
        val state = LuaState.create()
        LuaStdlib.openBase(state)
        LuaStdlib.openIo(state)

        try {
            assertEquals(
                LuaStatus.OK,
                state.load(
                    """
                    local handle = assert(io.open("${path.luaPath()}", "r"))
                    local handleCreateOk, handleIterator = pcall(function()
                        return handle:lines("?")
                    end)
                    local handleRunOk, handleMessage = pcall(handleIterator)
                    handle:close()

                    local moduleCreateOk, moduleIterator, stateValue, controlValue, closeFile =
                        pcall(io.lines, "${path.luaPath()}", "?")
                    local moduleRunOk, moduleMessage = pcall(moduleIterator, stateValue, controlValue)
                    closeFile:close()

                    return handleCreateOk, type(handleIterator), handleRunOk, handleMessage,
                        moduleCreateOk, type(moduleIterator), moduleRunOk, moduleMessage
                    """.trimIndent(),
                    "io-lines-delayed-format.lua",
                ),
            )
            assertEquals(LuaStatus.OK, state.pcall(0, -1), state.toString(-1))

            assertTrue(state.toBoolean(1))
            assertEquals("function", state.toString(2))
            assertFalse(state.toBoolean(3))
            assertEquals("bad argument #2 to 'lines' (invalid format)", state.toString(4))
            assertTrue(state.toBoolean(5))
            assertEquals("function", state.toString(6))
            assertFalse(state.toBoolean(7))
            assertEquals("bad argument #2 to 'io.lines' (invalid format)", state.toString(8))
        } finally {
            Files.deleteIfExists(path)
        }
    }

    @Test
    fun `io read formats execute incrementally and stop after failed reads`() {
        val path = Files.createTempFile("klua-io-read-format-order-", ".txt")
        val writeOnlyPath = Files.createTempFile("klua-io-read-format-direction-", ".txt")
        Files.writeString(path, "first\nsecond\n")
        val state = LuaState.create()
        LuaStdlib.openBase(state)
        LuaStdlib.openIo(state)

        try {
            assertEquals(
                LuaStatus.OK,
                state.load(
                    """
                    local handle = assert(io.open("${path.luaPath()}", "r"))
                    local laterOk, laterMessage = pcall(handle.read, handle, "l", "?")
                    local afterLaterError = handle:read("l")

                    handle:seek("set", 0)
                    local zeroOk, zeroMessage = pcall(handle.read, handle, 0, "?")
                    local afterZeroError = handle:read(1)

                    handle:seek("end", 0)
                    local eofCount = select("#", pcall(handle.read, handle, "l", "?"))
                    local eofOk, eofValue = pcall(handle.read, handle, "l", "?")
                    handle:close()

                    local iteratorHandle = assert(io.open("${path.luaPath()}", "r"))
                    local iterator = iteratorHandle:lines("l", "?")
                    local iteratorOk, iteratorMessage = pcall(iterator)
                    local afterIteratorError = iteratorHandle:read("l")
                    iteratorHandle:seek("end", 0)
                    local eofIterator = iteratorHandle:lines("l", "?")
                    local eofIteratorCount = select("#", pcall(eofIterator))
                    iteratorHandle:close()

                    local writeOnly = assert(io.open("${writeOnlyPath.luaPath()}", "w"))
                    local invalidDirectionOk, invalidDirectionMessage =
                        pcall(writeOnly.read, writeOnly, "?")
                    local directionOk, directionValue, directionMessage, directionCode =
                        pcall(writeOnly.read, writeOnly, "l", "?")
                    writeOnly:close()

                    return laterOk, laterMessage, afterLaterError,
                        zeroOk, zeroMessage, afterZeroError,
                        eofCount, eofOk, eofValue,
                        iteratorOk, iteratorMessage, afterIteratorError, eofIteratorCount,
                        invalidDirectionOk, invalidDirectionMessage,
                        directionOk, directionValue, type(directionMessage), type(directionCode)
                    """.trimIndent(),
                    "io-read-format-order.lua",
                ),
            )
            assertEquals(LuaStatus.OK, state.pcall(0, -1), state.toString(-1))

            assertFalse(state.toBoolean(1))
            assertEquals("bad argument #3 to 'read' (invalid format)", state.toString(2))
            assertEquals("second", state.toString(3))
            assertFalse(state.toBoolean(4))
            assertEquals("bad argument #3 to 'read' (invalid format)", state.toString(5))
            assertEquals("f", state.toString(6))
            assertEquals(2L, state.toInteger(7))
            assertTrue(state.toBoolean(8))
            assertTrue(state.isNil(9))
            assertFalse(state.toBoolean(10))
            assertEquals("bad argument #3 to 'lines' (invalid format)", state.toString(11))
            assertEquals("second", state.toString(12))
            assertEquals(1L, state.toInteger(13))
            assertFalse(state.toBoolean(14))
            assertEquals("bad argument #2 to 'read' (invalid format)", state.toString(15))
            assertTrue(state.toBoolean(16))
            assertTrue(state.isNil(17))
            assertEquals("string", state.toString(18))
            assertEquals("number", state.toString(19))
        } finally {
            Files.deleteIfExists(path)
            Files.deleteIfExists(writeOnlyPath)
        }
    }

    @Test
    fun `io read defers unsupported format values until their turn`() {
        val path = Files.createTempFile("klua-io-read-format-value-order-", ".txt")
        Files.writeString(path, "first\nsecond\n")
        val state = LuaState.create()
        LuaStdlib.openBase(state)
        LuaStdlib.openIo(state)

        try {
            assertEquals(
                LuaStatus.OK,
                state.load(
                    """
                    local direct = assert(io.open("${path.luaPath()}", "r"))
                    local directOk, directMessage = pcall(direct.read, direct, "l", {})
                    local directAfter = direct:read("l")
                    direct:close()

                    local firstInvalid = assert(io.open("${path.luaPath()}", "r"))
                    local firstOk, firstMessage = pcall(firstInvalid.read, firstInvalid, {})
                    local firstAfter = firstInvalid:read("l")
                    firstInvalid:close()

                    local default = io.input("${path.luaPath()}")
                    local defaultOk, defaultMessage = pcall(io.read, "l", function() end)
                    local defaultAfter = io.read("l")
                    default:close()

                    local linesHandle = assert(io.open("${path.luaPath()}", "r"))
                    local createOk, iterator = pcall(linesHandle.lines, linesHandle, "l", {})
                    local iteratorOk, iteratorMessage = pcall(iterator)
                    local linesAfter = linesHandle:read("l")
                    linesHandle:close()

                    return directOk, directMessage, directAfter,
                        firstOk, firstMessage, firstAfter,
                        defaultOk, defaultMessage, defaultAfter,
                        createOk, iteratorOk, iteratorMessage, linesAfter
                    """.trimIndent(),
                    "io-read-format-value-order.lua",
                ),
            )
            assertEquals(LuaStatus.OK, state.pcall(0, -1), state.toString(-1))

            assertFalse(state.toBoolean(1))
            assertEquals("bad argument #3 to 'read' (string expected)", state.toString(2))
            assertEquals("second", state.toString(3))
            assertFalse(state.toBoolean(4))
            assertEquals("bad argument #2 to 'read' (string expected)", state.toString(5))
            assertEquals("first", state.toString(6))
            assertFalse(state.toBoolean(7))
            assertEquals("bad argument #2 to 'read' (string expected)", state.toString(8))
            assertEquals("second", state.toString(9))
            assertTrue(state.toBoolean(10))
            assertFalse(state.toBoolean(11))
            assertEquals("bad argument #3 to 'lines' (string expected)", state.toString(12))
            assertEquals("second", state.toString(13))
        } finally {
            Files.deleteIfExists(path)
        }
    }

    @Test
    fun `io read supports source file formats`() {
        val path = Files.createTempFile("klua-io-read-", ".txt")
        Files.writeString(path, "  42 tail\n0x10 3.5\nabc")
        val state = LuaState.create()
        LuaStdlib.openBase(state)
        LuaStdlib.openIo(state)

        try {
            assertEquals(
                LuaStatus.OK,
                state.load(
                    """
                    local handle = assert(io.open("${path.luaPath()}", "r"))
                    local first = handle:read("n")
                    local bytes = handle:read(5)
                    local lineWithEnd = handle:read("L")
                    local hex, float = handle:read("*n", "*n")
                    local newline = handle:read("*L")
                    local numberFail, skipped = handle:read("n", 3)
                    local text = handle:read(3)
                    local eofProbe = handle:read(0)
                    local eofAll = handle:read("a")
                    handle:close()
                    return first, bytes, lineWithEnd, hex, float, newline,
                        numberFail, skipped, text, eofProbe, eofAll
                    """.trimIndent(),
                    "io-read-formats.lua",
                ),
            )
            assertEquals(LuaStatus.OK, state.pcall(0, -1), state.toString(-1))

            assertEquals(42L, state.toInteger(1))
            assertEquals(" tail", state.toString(2))
            assertEquals("\n", state.toString(3))
            assertEquals(16L, state.toInteger(4))
            assertEquals(3.5, state.toNumber(5) ?: error("missing float"), 0.0)
            assertEquals("\n", state.toString(6))
            assertTrue(state.isNil(7))
            assertTrue(state.isNil(8))
            assertEquals("abc", state.toString(9))
            assertTrue(state.isNil(10))
            assertEquals("", state.toString(11))
        } finally {
            Files.deleteIfExists(path)
        }
    }

