        assertEquals(1L, state.toInteger(4))
        assertEquals(2L, state.toInteger(5))
        assertEquals("return", state.toString(6))
        assertEquals(1L, state.toInteger(7))
        assertEquals(2L, state.toInteger(8))
    }

    @Test
