        assertEquals("C", state.toString(9))
        assertEquals(1L, state.toInteger(10))
        assertEquals(1L, state.toInteger(11))
        assertEquals("(C temporary)", state.toString(12))
        assertEquals(4L, state.toInteger(13))
    }

