        assertEquals("(C temporary)", state.toString(6))
        assertEquals("(C temporary)", state.toString(7))
        assertEquals("nil", state.toString(8))
        assertEquals(11L, state.toInteger(9))
        assertEquals(22L, state.toInteger(10))
    }

