        assertTrue(state.toBoolean(3))
        assertTrue(state.toBoolean(4))
        assertEquals("done", state.toString(5))
        assertEquals("changed resume", state.toString(6))
        assertEquals(
            "call:target,call:yield,return:yield,return:target",
            state.toString(7),
        )
        assertEquals("dead", state.toString(8))
    }

    @Test
    fun `xpcall recovers a resumed target on its coroutine hook state`() {
        val state = LuaState.create()
        LuaStdlib.openLibs(state)

        assertEquals(
            LuaStatus.OK,
            state.load(
                """
                local records = {}
                local target
                local handler
                local function hook(event)
                    local info = debug.getinfo(2, "f")
                    if info.func == target then
                        records[#records + 1] = event .. ":target"
                    elseif info.func == handler then
                        records[#records + 1] = event .. ":handler"
                    elseif info.func == math.abs then
                        records[#records + 1] = event .. ":abs"
                        if event == "call" then
                            debug.setlocal(2, 1, -42)
                        end
                    end
                end
                target = function()
                    coroutine.yield("pause")
                    error("boom", 0)
                end
                handler = function(message)
                    return message .. ":" .. math.abs(-1)
                end
                local co = coroutine.create(function()
                    return xpcall(target, handler)
                end)
                debug.sethook(co, hook, "cr", 0)

                local firstOk, paused = coroutine.resume(co)
                local installed, mask, count = debug.gethook(co)
                local secondOk, protectedOk, message = coroutine.resume(co)
                local retained, retainedMask, retainedCount = debug.gethook(co)
                debug.sethook(co)
                return firstOk, paused, installed == hook, mask, count,
                    secondOk, protectedOk, message,
                    retained == hook, retainedMask, retainedCount,
                    table.concat(records, ","), coroutine.status(co)
                """.trimIndent(),
                "debug-hook-xpcall-resume-error.lua",
            ),
        )
        assertEquals(LuaStatus.OK, state.pcall(0, -1), state.toString(-1))

        assertTrue(state.toBoolean(1))
        assertEquals("pause", state.toString(2))
        assertTrue(state.toBoolean(3))
        assertEquals("cr", state.toString(4))
        assertEquals(0L, state.toInteger(5))
        assertTrue(state.toBoolean(6))
        assertFalse(state.toBoolean(7))
        assertEquals("boom:42", state.toString(8))
        assertTrue(state.toBoolean(9))
        assertEquals("cr", state.toString(10))
        assertEquals(0L, state.toInteger(11))
        assertEquals(
            "call:target,call:handler,call:abs,return:abs,return:handler",
            state.toString(12),
        )
        assertEquals("dead", state.toString(13))
    }

    @Test
    fun `nested protected calls shadow outer error handlers`() {
        val state = LuaState.create()
        LuaStdlib.openLibs(state)

        assertEquals(
            LuaStatus.OK,
            state.load(
                """
                local outerCalls = 0
                local innerCalls = 0
                local outerOk, innerOk, innerMessage = xpcall(function()
                    local plainOk, plainMessage = pcall(function()
                        error("plain", 0)
                    end)
                    local nestedOk, nestedMessage = xpcall(function()
                        error("nested", 0)
                    end, function(message)
                        innerCalls = innerCalls + 1
                        return "inner:" .. message
                    end)
                    return plainOk, plainMessage, nestedOk, nestedMessage
                end, function(message)
                    outerCalls = outerCalls + 1
                    return "outer:" .. message
                end)
                return outerOk, innerOk, innerMessage, innerCalls, outerCalls
                """.trimIndent(),
                "nested-protected-error-handlers.lua",
            ),
        )
        assertEquals(LuaStatus.OK, state.pcall(0, -1), state.toString(-1))

        assertTrue(state.toBoolean(1))
        assertFalse(state.toBoolean(2))
        assertEquals("plain", state.toString(3))
        assertEquals(1L, state.toInteger(4))
        assertEquals(0L, state.toInteger(5))
    }

    @Test
    fun `debug native call mutation precedes a target failure without a return event`() {
        val state = LuaState.create()
        LuaStdlib.openLibs(state)
        var observedArgument: Any? = null
        state.register("failingNative") { context ->
            observedArgument = context.get(1)
            throw LuaRuntimeException("native failure")
        }

        assertEquals(
            LuaStatus.OK,
            state.load(
                """
                local events = {}
                local function hook(event)
                    local info = debug.getinfo(2, "n")
                    if info.name == "failingNative" then
                        events[#events + 1] = event
                        debug.setlocal(2, 1, "mutated")
                    end
                end
                local co = coroutine.create(function()
                    return failingNative("original")
                end)
                debug.sethook(co, hook, "cr", 0)
                local ok, message = coroutine.resume(co)
                debug.sethook(co)
                return ok, message, events[1], #events
                """.trimIndent(),
                "debug-hook-native-failure-setlocal.lua",
            ),
        )
        assertEquals(LuaStatus.OK, state.pcall(0, -1), state.toString(-1))

        assertFalse(state.toBoolean(1))
        assertEquals("native failure", state.toString(2))
        assertEquals("call", state.toString(3))
        assertEquals(1L, state.toInteger(4))
        assertEquals("mutated", observedArgument)
    }

    @Test
    fun `debug call hook reports Lua tail calls without a replaced caller return`() {
        val state = LuaState.create()
        LuaStdlib.openLibs(state)

        assertEquals(
            LuaStatus.OK,
            state.load(
                """
                local leaf
                local relay
                local records = {}
                leaf = function(left, right)
                    return left + right, left - right
                end
                relay = function(...)
                    return leaf(...)
                end
                local function hook(event, line)
                    local info = debug.getinfo(2, "frt")
                    if info.func == relay then
                        records[#records + 1] = event .. ":relay:" .. info.ftransfer .. ":" .. info.ntransfer
                    elseif info.func == leaf then
                        records[#records + 1] = event .. ":leaf:" .. info.ftransfer .. ":" .. info.ntransfer
                    end
                end

                debug.sethook(hook, "cr", 0)
                local sum, difference = relay(7, 2)
                debug.sethook()
                return sum, difference, records[1], records[2], records[3], #records
                """.trimIndent(),
                "debug-hook-tail-call.lua",
            ),
        )
        assertEquals(LuaStatus.OK, state.pcall(0, -1), state.toString(-1))

        assertEquals(9L, state.toInteger(1))
        assertEquals(5L, state.toInteger(2))
        assertEquals("call:relay:1:0", state.toString(3))
        assertEquals("tail call:leaf:1:2", state.toString(4))
        assertEquals("return:leaf:1:2", state.toString(5))
        assertEquals(3L, state.toInteger(6))
    }

    @Test
    fun `debug tail hook state survives a yielded target thread`() {
        val state = LuaState.create()
        LuaStdlib.openLibs(state)

        assertEquals(
            LuaStatus.OK,
            state.load(
                """
                local leaf
                local relay
                local records = {}
                leaf = function(value)
                    coroutine.yield("pause")
                    return value + 1
                end
                relay = function(value)
                    return leaf(value)
                end
                local function hook(event)
                    local info = debug.getinfo(2, "fr")
                    if info.func == relay then
                        records[#records + 1] = event .. ":relay"
                    elseif info.func == leaf then
                        records[#records + 1] = event .. ":leaf"
                    end
                end

                local co = coroutine.create(relay)
                debug.sethook(co, hook, "cr", 0)
                local firstOk, paused = coroutine.resume(co, 8)
                local suspendedHook, suspendedMask = debug.gethook(co)
                local secondOk, result = coroutine.resume(co)
                local deadHook, deadMask = debug.gethook(co)
                debug.sethook(co)
                return firstOk, paused, suspendedHook == hook, suspendedMask,
                    secondOk, result, deadHook == hook, deadMask,
                    records[1], records[2], records[3], #records
                """.trimIndent(),
                "debug-hook-yielded-tail-call.lua",
            ),
        )
        assertEquals(LuaStatus.OK, state.pcall(0, -1), state.toString(-1))

        assertTrue(state.toBoolean(1))
        assertEquals("pause", state.toString(2))
        assertTrue(state.toBoolean(3))
        assertEquals("cr", state.toString(4))
        assertTrue(state.toBoolean(5))
        assertEquals(9L, state.toInteger(6))
        assertTrue(state.toBoolean(7))
        assertEquals("cr", state.toString(8))
        assertEquals("call:relay", state.toString(9))
        assertEquals("tail call:leaf", state.toString(10))
        assertEquals("return:leaf", state.toString(11))
        assertEquals(3L, state.toInteger(12))
    }

    @Test
    fun `debug native return hook resumes at the yield boundary`() {
        val state = LuaState.create()
        LuaStdlib.openLibs(state)

        assertEquals(
            LuaStatus.OK,
            state.load(
                """
                local records = {}
                local function hook(event)
                    local info = debug.getinfo(2, "fr")
                    if info.func == coroutine.yield then
                        local name, value = debug.getlocal(2, 1)
                        local setName = debug.setlocal(
                            2,
                            1,
                            event == "call" and "changed pause" or "changed resume"
                        )
                        records[#records + 1] = event
                        records[#records + 1] = info.ftransfer
                        records[#records + 1] = info.ntransfer
                        records[#records + 1] = name
                        records[#records + 1] = value
                        records[#records + 1] = setName
                    end
                end
                local co = coroutine.create(function()
                    return coroutine.yield("pause")
                end)
                debug.sethook(co, hook, "cr", 0)
                local firstOk, paused = coroutine.resume(co)
                local secondOk, resumed = coroutine.resume(co, "resume")
                debug.sethook(co)
                return firstOk, paused, secondOk, resumed,
                    records[1], records[2], records[3], records[4], records[5],
                    records[6], records[7], records[8], records[9], records[10],
                    records[11], records[12]
                """.trimIndent(),
                "debug-hook-native-yield-return.lua",
            ),
        )
        assertEquals(LuaStatus.OK, state.pcall(0, -1), state.toString(-1))

        assertTrue(state.toBoolean(1))
        assertEquals("changed pause", state.toString(2))
        assertTrue(state.toBoolean(3))
        assertEquals("changed resume", state.toString(4))
        assertEquals("call", state.toString(5))
        assertEquals(1L, state.toInteger(6))
        assertEquals(1L, state.toInteger(7))
        assertEquals("(C temporary)", state.toString(8))
        assertEquals("pause", state.toString(9))
        assertEquals("(C temporary)", state.toString(10))
        assertEquals("return", state.toString(11))
        assertEquals(1L, state.toInteger(12))
        assertEquals(1L, state.toInteger(13))
        assertEquals("(C temporary)", state.toString(14))
        assertEquals("resume", state.toString(15))
        assertEquals("(C temporary)", state.toString(16))
    }

    @Test
    fun `debug setlocal mutates host continuation call and return values`() {
        val state = LuaState.create()
        LuaStdlib.openLibs(state)
        state.register(
            "hostYieldOnce",
            LuaYieldableFunction { context ->
                try {
                    context.yield(listOf("first", context.get(1)))
                } catch (yield: LuaYieldException) {
                    throw yield.withContinuation { resumed ->
                        LuaReturn.of("done", resumed.firstOrNull())
                    }
                }
            },
        )

        assertEquals(
            LuaStatus.OK,
            state.load(
                """
                local records = {}
                local co
                local function hook(event)
                    local info = debug.getinfo(2, "f")
                    if info.func == hostYieldOnce then
                        records[#records + 1] = event
                        records[#records + 1] = debug.setlocal(
                            co,
                            2,
                            1,
                            event == "call" and "changed start" or "changed done"
                        )
                        if event == "return" then
                            records[#records + 1] = debug.setlocal(co, 2, 2, "changed finish")
                        end
                    end
                end
                co = coroutine.create(function(value)
                    return hostYieldOnce(value)
                end)
                debug.sethook(co, hook, "cr", 0)
                local firstOk, marker, firstValue = coroutine.resume(co, "start")
                local secondOk, done, finalValue = coroutine.resume(co, "finish")
                debug.sethook(co)
                return firstOk, marker, firstValue, secondOk, done, finalValue,
                    records[1], records[2], records[3], records[4], records[5]
                """.trimIndent(),
                "debug-hook-host-continuation-setlocal.lua",
            ),
        )
        assertEquals(LuaStatus.OK, state.pcall(0, -1), state.toString(-1))

        assertTrue(state.toBoolean(1))
        assertEquals("first", state.toString(2))
        assertEquals("changed start", state.toString(3))
        assertTrue(state.toBoolean(4))
        assertEquals("changed done", state.toString(5))
        assertEquals("changed finish", state.toString(6))
        assertEquals("call", state.toString(7))
        assertEquals("(C temporary)", state.toString(8))
        assertEquals("return", state.toString(9))
        assertEquals("(C temporary)", state.toString(10))
        assertEquals("(C temporary)", state.toString(11))
    }

