    @Test
    fun `tonumber converts numbers and decimal strings`() {
        val state = LuaState.create()
        LuaStdlib.openBase(state)

        assertEquals(
            LuaStatus.OK,
            state.load(
                """
                return tonumber("42"),
                    tonumber("3.5"),
                    tonumber("0x1.8p1"),
                    tonumber("0x1.8"),
                    tonumber("0x.8"),
                    tonumber("bad"),
                    tonumber("NaN"),
                    tonumber("Infinity"),
                    tonumber("-Infinity"),
                    tonumber(7),
                    tonumber("1e9999"),
                    tonumber("-1e-9999"),
                    tonumber("1.5f"),
                    tonumber("0x1p0d")
                """.trimIndent(),
                "tonumber.lua",
            ),
        )
        assertEquals(LuaStatus.OK, state.pcall(0, -1))

        assertEquals(42L, state.toInteger(1))
        assertEquals(3.5, state.toNumber(2))
        assertEquals(3.0, state.toNumber(3))
        assertEquals(1.5, state.toNumber(4))
        assertEquals(0.5, state.toNumber(5))
        assertTrue(state.isNil(6))
        assertTrue(state.isNil(7))
        assertTrue(state.isNil(8))
        assertTrue(state.isNil(9))
        assertEquals(7L, state.toInteger(10))
        assertEquals(Double.POSITIVE_INFINITY, state.toNumber(11))
        assertEquals(
            java.lang.Double.doubleToRawLongBits(-0.0),
            java.lang.Double.doubleToRawLongBits(state.toNumber(12) ?: error("missing underflow result")),
        )
        assertTrue(state.isNil(13))
        assertTrue(state.isNil(14))
    }

    @Test
    fun `tonumber accepts locale decimal points`() {
        val previousLocale = Locale.getDefault()
        Locale.setDefault(Locale.GERMANY)
        val state = LuaState.create()
        LuaStdlib.openBase(state)

        try {
            assertEquals(
                LuaStatus.OK,
                state.load(
                    """
                    return tonumber("1,5"),
                        tonumber("0x1,8p1"),
                        tonumber("0x1,8"),
                        tonumber("2.5"),
                        tonumber("1,5.0"),
                        tonumber("1,5", 10)
                    """.trimIndent(),
                    "tonumber-locale-decimal.lua",
                ),
            )
            assertEquals(LuaStatus.OK, state.pcall(0, -1), state.toString(-1))

            assertEquals(1.5, state.toNumber(1) ?: error("missing locale decimal result"), 0.0)
            assertEquals(3.0, state.toNumber(2) ?: error("missing locale hex result"), 0.0)
            assertEquals(1.5, state.toNumber(3) ?: error("missing locale exponentless hex result"), 0.0)
            assertEquals(2.5, state.toNumber(4) ?: error("missing dot fallback result"), 0.0)
            assertTrue(state.isNil(5))
            assertTrue(state.isNil(6))
        } finally {
            Locale.setDefault(previousLocale)
        }
    }

