    @Test
    fun `pairs metamethod can yield before returning iterator results`() {
        val state = LuaState.create()
        LuaStdlib.openLibs(state)

        assertEquals(
            LuaStatus.OK,
            state.load(
                """
                local target = setmetatable({}, {
                    __pairs = function(self)
                        local resumed = coroutine.yield("paused", self)
                        return function(state, key)
                            if key == nil then
                                return resumed, state.marker
                            end
                        end, self, nil, "closing"
                    end,
                })
                target.marker = "value"
                local co = coroutine.create(function()
                    local iterator, state, key, closing = pairs(target)
                    local firstKey, firstValue = iterator(state, key)
                    return firstKey, firstValue, closing
                end)
                local firstOk, marker, yieldedSelf = coroutine.resume(co)
                local secondOk, firstKey, firstValue, closing = coroutine.resume(co, "resumed")
                return firstOk, marker, yieldedSelf == target,
                    secondOk, firstKey, firstValue, closing, coroutine.status(co)
                """.trimIndent(),
                "pairs-yielding-metamethod.lua",
            ),
        )
        assertEquals(LuaStatus.OK, state.pcall(0, -1), state.toString(-1))

        assertTrue(state.toBoolean(1))
        assertEquals("paused", state.toString(2))
        assertTrue(state.toBoolean(3))
        assertTrue(state.toBoolean(4))
        assertEquals("resumed", state.toString(5))
        assertEquals("value", state.toString(6))
        assertEquals("closing", state.toString(7))
        assertEquals("dead", state.toString(8))
    }

    @Test
    fun `pairs calls callable pairs metamethod values`() {
        val state = LuaState.create()
        LuaStdlib.openBase(state)

        assertEquals(
            LuaStatus.OK,
            state.load(
                """
                local callable = setmetatable({prefix = "called"}, {
                    __call = function(self, target)
                        local done = false
                        return function(state, key)
                            if done then
                                return nil
                            end
                            done = true
                            return "seen", self.prefix .. ":" .. state.name .. ":" .. key
                        end, target, "start", "closed"
                    end,
                })
                local target = setmetatable({name = "target"}, {
                    __pairs = callable,
                })

                local iterator, stateValue, key, closing = pairs(target)
                local firstKey, firstValue = iterator(stateValue, key)
                local done = iterator(stateValue, firstKey)
                return stateValue == target, key, closing, firstKey, firstValue, done,
                    select("#", pairs(target))
                """.trimIndent(),
                "pairs-callable-metamethod.lua",
            ),
        )
        assertEquals(LuaStatus.OK, state.pcall(0, -1), state.toString(-1))

        assertTrue(state.toBoolean(1))
        assertEquals("start", state.toString(2))
        assertEquals("closed", state.toString(3))
        assertEquals("seen", state.toString(4))
        assertEquals("called:target:start", state.toString(5))
        assertTrue(state.isNil(6))
        assertEquals(4L, state.toInteger(7))
    }

