    @Test
    fun `package reuses shared registry tables across reopen and global replacement`() {
        val state = LuaState.create()
        LuaStdlib.openLibs(state)

        assertEquals(
            LuaStatus.OK,
            state.load(
                """
                local registry = debug.getregistry()
                registry._LOADED.persisted = "registry-loaded"
                registry._PRELOAD.from_registry = function(name, data)
                    return name .. "@" .. data
                end
                registry.LUA_NOENV = true
                package = { replacement = true }
                return package.replacement
                """.trimIndent(),
                "registry-package-prepare.lua",
            ),
        )
        assertEquals(LuaStatus.OK, state.pcall(0, 1), state.toString(-1))
        assertTrue(state.toBoolean(-1))
        state.setTop(0)

        LuaStdlib.openPackage(state)

        assertEquals(
            LuaStatus.OK,
            state.load(
                """
                local registry = debug.getregistry()
                local cached, cachedExtra = require("persisted")
                local preloaded, preloadExtra = require("from_registry")
                return registry._LOADED == package.loaded,
                    registry._PRELOAD == package.preload,
                    cached, cachedExtra,
                    preloaded, preloadExtra,
                    registry.LUA_NOENV, package.replacement,
                    package.path
                """.trimIndent(),
                "registry-package-reopen.lua",
            ),
        )
        assertEquals(LuaStatus.OK, state.pcall(0, -1), state.toString(-1))

        assertTrue(state.toBoolean(1))
        assertTrue(state.toBoolean(2))
        assertEquals("registry-loaded", state.toString(3))
        assertTrue(state.isNil(4))
        assertEquals("from_registry@:preload:", state.toString(5))
        assertEquals(":preload:", state.toString(6))
        assertTrue(state.toBoolean(7))
        assertTrue(state.isNil(8))
        assertEquals(
            LuaPackageLibrary.resolvePackagePath(
                "LUA_PATH",
                LuaPackageLibrary.defaultLuaPath,
                environmentEnabled = false,
            ),
            state.toString(9),
        )
    }

    @Test
    fun `registry main thread survives coroutine reopen and is isolated per state`() {
        val state = LuaState.create()
        LuaStdlib.openLibs(state)

        assertEquals(
            LuaStatus.OK,
            state.load(
                """
                savedMainThread = coroutine.running()
                return savedMainThread == debug.getregistry()[3]
                """.trimIndent(),
                "registry-main-thread-before-reopen.lua",
            ),
        )
        assertEquals(LuaStatus.OK, state.pcall(0, 1), state.toString(-1))
        assertTrue(state.toBoolean(-1))
        state.setTop(0)

        LuaStdlib.openCoroutine(state)

        assertEquals(
            LuaStatus.OK,
            state.load(
                """
                local running, isMain = coroutine.running()
                return running == savedMainThread,
                    running == debug.getregistry()[3], isMain,
                    select("#", coroutine.running())
                """.trimIndent(),
                "registry-main-thread-after-reopen.lua",
            ),
        )
        assertEquals(LuaStatus.OK, state.pcall(0, -1), state.toString(-1))
        assertTrue(state.toBoolean(1))
        assertTrue(state.toBoolean(2))
        assertTrue(state.toBoolean(3))
        assertEquals(2L, state.toInteger(4))

        val otherState = LuaState.create()
        LuaStdlib.openCoroutine(otherState)
        state.pushRegistryInteger(3)
        otherState.pushRegistryInteger(3)
        assertTrue(state.toUserData(-1) !== otherState.toUserData(-1))
    }

