    @Test
    fun `os time normalization writes missing fields through newindex`() {
        val state = LuaState.create()
        LuaStdlib.openBase(state)
        LuaStdlib.openString(state)
        LuaStdlib.openOs(state)
        LuaStdlib.openDebug(state)

        assertEquals(
            LuaStatus.OK,
            state.load(
                """
                local writes = {}
                local date = setmetatable({
                    year = 2020,
                    month = 1,
                    day = 2,
                }, {
                    __newindex = function(_, key, value)
                        writes[key] = value
                    end,
                })
                local timestamp = os.time(date)
                local tableWrites = {}
                local tableDate = setmetatable({
                    year = 2020,
                    month = 1,
                    day = 2,
                }, {
                    __newindex = tableWrites,
                })
                os.time(tableDate)
                local nestedWrites = {}
                local proxy = setmetatable({}, {
                    __newindex = function(_, key, value)
                        nestedWrites[key] = value
                    end,
                })
                local nestedDate = setmetatable({
                    year = 2020,
                    month = 1,
                    day = 2,
                }, {
                    __newindex = proxy,
                })
                os.time(nestedDate)
                local originalStringMetatable = debug.getmetatable("")
                local stringWrites = {}
                debug.setmetatable("", {
                    __newindex = stringWrites,
                })
                local stringDate = setmetatable({
                    year = 2020,
                    month = 1,
                    day = 2,
                }, {
                    __newindex = "sink",
                })
                os.time(stringDate)
                debug.setmetatable("", originalStringMetatable)
                return type(timestamp),
                    date.year, date.month, date.day,
                    rawget(date, "hour"),
                    writes.hour, writes.min, writes.sec,
                    writes.wday ~= nil, writes.yday ~= nil, writes.isdst ~= nil,
                    rawget(tableDate, "hour"),
                    tableWrites.hour, tableWrites.min, tableWrites.sec,
                    tableWrites.wday ~= nil, tableWrites.yday ~= nil, tableWrites.isdst ~= nil,
                    rawget(proxy, "hour"),
                    nestedWrites.hour, nestedWrites.min, nestedWrites.sec,
                    nestedWrites.wday ~= nil, nestedWrites.yday ~= nil, nestedWrites.isdst ~= nil,
                    rawget(stringDate, "hour"),
                    stringWrites.hour, stringWrites.min, stringWrites.sec,
                    stringWrites.wday ~= nil, stringWrites.yday ~= nil, stringWrites.isdst ~= nil
                """.trimIndent(),
                "os-time-newindex-normalization.lua",
            ),
        )
        assertEquals(LuaStatus.OK, state.pcall(0, -1), state.toString(-1))

        assertEquals("number", state.toString(1))
        assertEquals(2020L, state.toInteger(2))
        assertEquals(1L, state.toInteger(3))
        assertEquals(2L, state.toInteger(4))
        assertTrue(state.isNil(5))
        assertEquals(12L, state.toInteger(6))
        assertEquals(0L, state.toInteger(7))
        assertEquals(0L, state.toInteger(8))
        assertTrue(state.toBoolean(9))
        assertTrue(state.toBoolean(10))
        assertTrue(state.toBoolean(11))
        assertTrue(state.isNil(12))
        assertEquals(12L, state.toInteger(13))
        assertEquals(0L, state.toInteger(14))
        assertEquals(0L, state.toInteger(15))
        assertTrue(state.toBoolean(16))
        assertTrue(state.toBoolean(17))
        assertTrue(state.toBoolean(18))
        assertTrue(state.isNil(19))
        assertEquals(12L, state.toInteger(20))
        assertEquals(0L, state.toInteger(21))
        assertEquals(0L, state.toInteger(22))
        assertTrue(state.toBoolean(23))
        assertTrue(state.toBoolean(24))
        assertTrue(state.toBoolean(25))
        assertTrue(state.isNil(26))
        assertEquals(12L, state.toInteger(27))
        assertEquals(0L, state.toInteger(28))
        assertEquals(0L, state.toInteger(29))
        assertTrue(state.toBoolean(30))
        assertTrue(state.toBoolean(31))
        assertTrue(state.toBoolean(32))
    }

    @Test
    fun `os rename and remove operate on files`() {
        val windows = System.getProperty("os.name").startsWith("Windows", ignoreCase = true)
        val root = Files.createTempDirectory("klua-os-files")
        val source = root.resolve("source.txt")
        val target = root.resolve("target.txt")
        val replacementSource = root.resolve("replacement-source.txt")
        val replacementTarget = root.resolve("replacement-target.txt")
        val emptyDirectory = root.resolve("empty")
        Files.writeString(source, "payload")
        Files.writeString(replacementSource, "new")
        Files.writeString(replacementTarget, "old")
        Files.createDirectory(emptyDirectory)
        try {
            val state = LuaState.create()
            LuaStdlib.openBase(state)
            LuaStdlib.openOs(state)

            assertEquals(
                LuaStatus.OK,
                state.load(
                    """
                    local renameCount, renamed = (function(...)
                        return select("#", ...), ...
                    end)(os.rename("${source.luaPath()}", "${target.luaPath()}"))
                    local removeCount, removed = (function(...)
                        return select("#", ...), ...
                    end)(os.remove("${target.luaPath()}"))
                    local directoryRemoved = os.remove("${emptyDirectory.luaPath()}")
                    local replaced, replaceMessage, replaceCode =
                        os.rename("${replacementSource.luaPath()}", "${replacementTarget.luaPath()}")
                    return renameCount, renamed, removeCount, removed, directoryRemoved,
                        replaced, replaceMessage, type(replaceCode)
                    """.trimIndent(),
                    "os-rename-remove.lua",
                ),
            )
            assertEquals(LuaStatus.OK, state.pcall(0, -1), state.toString(-1))

            assertEquals(1L, state.toInteger(1))
            assertTrue(state.toBoolean(2))
            assertEquals(1L, state.toInteger(3))
            assertTrue(state.toBoolean(4))
            assertTrue(state.toBoolean(5))
            assertFalse(Files.exists(source))
            assertFalse(Files.exists(target))
            assertFalse(Files.exists(emptyDirectory))
            if (windows) {
                assertTrue(state.isNil(6))
                assertEquals("string", state.typeName(7))
                assertEquals("number", state.toString(8))
                assertEquals("new", Files.readString(replacementSource))
                assertEquals("old", Files.readString(replacementTarget))
            } else {
                assertTrue(state.toBoolean(6))
                assertTrue(state.isNil(7))
                assertEquals("nil", state.toString(8))
                assertFalse(Files.exists(replacementSource))
                assertEquals("new", Files.readString(replacementTarget))
            }
        } finally {
            Files.deleteIfExists(source)
            Files.deleteIfExists(target)
            Files.deleteIfExists(replacementSource)
            Files.deleteIfExists(replacementTarget)
            Files.deleteIfExists(emptyDirectory)
            Files.deleteIfExists(root)
        }
    }

    @Test
    fun `os filesystem names use source c string boundaries`() {
        val root = Files.createTempDirectory("klua-os-files-c-string-")
        val source = root.resolve("source.txt")
        val target = root.resolve("target.txt")
        val missing = root.resolve("missing.txt")
        Files.writeString(source, "payload")
        val state = LuaState.create()
        LuaStdlib.openBase(state)
        LuaStdlib.openOs(state)

        try {
            assertEquals(
                LuaStatus.OK,
                state.load(
                    """
                    local suffix = "\0ignored"
                    local renameCount, renamed = (function(...)
                        return select("#", ...), ...
                    end)(os.rename(
                        "${source.luaPath()}" .. suffix,
                        "${target.luaPath()}" .. suffix,
                        "ignored"
                    ))
                    local removeCount, removed = (function(...)
                        return select("#", ...), ...
                    end)(os.remove("${target.luaPath()}" .. suffix, "ignored"))
                    local missingCount, missingValue, missingMessage, missingCode = (function(...)
                        return select("#", ...), ...
                    end)(os.remove("${missing.luaPath()}" .. suffix, "ignored"))
                    local renameMissingCount, renameMissingValue,
                        renameMissingMessage, renameMissingCode = (function(...)
                        return select("#", ...), ...
                    end)(os.rename(
                        "${missing.luaPath()}" .. suffix,
                        "${target.luaPath()}" .. suffix,
                        "ignored"
                    ))
                    return renameCount, renamed, removeCount, removed,
                        missingCount, missingValue, missingMessage, missingCode,
                        renameMissingCount, renameMissingValue,
                        renameMissingMessage, renameMissingCode
                    """.trimIndent(),
                    "os-filesystem-c-string-boundaries.lua",
                ),
            )
            assertEquals(LuaStatus.OK, state.pcall(0, -1), state.toString(-1))

            assertEquals(1L, state.toInteger(1))
            assertTrue(state.toBoolean(2))
            assertEquals(1L, state.toInteger(3))
            assertTrue(state.toBoolean(4))
            assertEquals(3L, state.toInteger(5))
            assertTrue(state.isNil(6))
            assertTrue(state.toString(7)?.startsWith("$missing: ") == true, state.toString(7))
            assertFalse(state.toString(7)?.contains("ignored") == true, state.toString(7))
            assertEquals(1L, state.toInteger(8))
            assertEquals(3L, state.toInteger(9))
            assertTrue(state.isNil(10))
            assertEquals("string", state.typeName(11))
            assertFalse(state.toString(11)?.contains("ignored") == true, state.toString(11))
            assertEquals(1L, state.toInteger(12))
            assertFalse(Files.exists(source))
            assertFalse(Files.exists(target))
        } finally {
            Files.deleteIfExists(source)
            Files.deleteIfExists(target)
            Files.deleteIfExists(missing)
            Files.deleteIfExists(root)
        }
    }

