            statusState.load("""return coroutine.status("not-thread")""", "coroutine-status-error.lua"),
        )
        assertEquals(LuaStatus.RUNTIME_ERROR, statusState.pcall(0, -1))
        assertIs<LuaRuntimeException>(statusState.getLastError())
