            closeState.load("""return coroutine.close("not-thread")""", "coroutine-close-error.lua"),
        )
        assertEquals(LuaStatus.RUNTIME_ERROR, closeState.pcall(0, -1))
        assertIs<LuaRuntimeException>(closeState.getLastError())
