        assertEquals("float", state.toString(5))
        assertTrue(state.toBoolean(6))
        assertEquals("float", state.toString(7))
        assertTrue(state.toBoolean(8))
        assertEquals("integer", state.toString(9))
        assertTrue(state.toBoolean(10))
        assertEquals("integer", state.toString(11))
        for (index in 12..17) {
            assertTrue(state.isNil(index), "compatibility field at index $index")
        }
    }

    @Test
    fun `openMath replaces its table while preserving light function identity and random state ownership`() {
        val state = LuaState.create()
        LuaStdlib.openBase(state)
        LuaStdlib.openMath(state)

        assertEquals(
            LuaStatus.OK,
            state.load(
                """
                oldMath = math
                oldAbs = math.abs
                oldSin = math.sin
                oldRandom = math.random
                oldRandomseed = math.randomseed
                oldMath.randomseed(0x1234, 0x5678)
                oldFirst = oldMath.random()
                oldMath.abs = "mutated"
                return true
                """.trimIndent(),
                "math-before-reopen.lua",
            ),
        )
        assertEquals(LuaStatus.OK, state.pcall(0, 1), state.toString(-1))
        assertTrue(state.toBoolean(-1))
        state.setTop(0)

        LuaStdlib.openMath(state)

        assertEquals(
            LuaStatus.OK,
            state.load(
                """
                local newMath = math
                newMath.randomseed(0x1234, 0x5678)
                local newFirst = newMath.random()
                local oldSecond = oldMath.random()
                local newSecond = newMath.random()
                return oldMath ~= newMath,
                    oldAbs == newMath.abs, oldSin == newMath.sin,
                    oldRandom ~= newMath.random,
                    oldRandomseed ~= newMath.randomseed,
                    oldMath.abs == "mutated", type(newMath.abs) == "function",
                    oldFirst == newFirst, oldSecond == newSecond,
                    oldMath.random ~= newMath.random,
                    oldMath.randomseed ~= newMath.randomseed
                """.trimIndent(),
                "math-after-reopen.lua",
            ),
        )
        assertEquals(LuaStatus.OK, state.pcall(0, -1), state.toString(-1))

        for (index in 1..11) {
            assertTrue(state.toBoolean(index), "math reopen result $index")
        }
    }

    @Test
    fun `math numeric arguments accept locale decimal numeric strings`() {
        val previousLocale = Locale.getDefault()
        try {
            Locale.setDefault(Locale.GERMANY)
            val state = LuaState.create()
            LuaStdlib.openBase(state)
            LuaStdlib.openMath(state)

            assertEquals(
                LuaStatus.OK,
                state.load(
                    """
                    math.randomseed("1,0", "2,0")
                    local randomValue = math.random("1,0", "3,0")
                    local fractionalOk, fractionalMessage = pcall(math.random, "1,5")
                    local mixedOk, mixedMessage = pcall(math.abs, "1,0.0")
                    return math.abs("-1,5"),
                        math.floor("2,9"),
                        math.ceil("2,1"),
                        math.fmod("5,5", "2,0"),
                        math.ldexp("1,5", "1,0"),
                        math.ult("1,0", "2,0"),
                        math.tointeger("0x1,8p1"),
                        randomValue >= 1 and randomValue <= 3,
                        fractionalOk, fractionalMessage,
                        mixedOk, mixedMessage
                    """.trimIndent(),
                    "math-locale-decimal-numeric-arguments.lua",
                ),
            )
            assertEquals(LuaStatus.OK, state.pcall(0, -1), state.toString(-1))

            assertEquals(1.5, state.toNumber(1) ?: error("missing abs result"), 0.0)
            assertEquals(2L, state.toInteger(2))
            assertEquals(3L, state.toInteger(3))
            assertEquals(1.5, state.toNumber(4) ?: error("missing fmod result"), 0.0)
            assertEquals(3.0, state.toNumber(5) ?: error("missing ldexp result"), 0.0)
            assertTrue(state.toBoolean(6))
            assertEquals(3L, state.toInteger(7))
            assertTrue(state.toBoolean(8))
            assertFalse(state.toBoolean(9))
            assertEquals("bad argument #1 to 'random' (number has no integer representation)", state.toString(10))
            assertFalse(state.toBoolean(11))
            assertEquals("bad argument #1 to 'abs' (number expected)", state.toString(12))
        } finally {
            Locale.setDefault(previousLocale)
        }
    }

