        assertEquals(
            LuaStatus.OK,
            state.load(
                """
                local parts = {}
                for value = 0, 255 do
                    parts[#parts + 1] = string.char(value)
                end
                local all = table.concat(parts)
                local rebuilt = string.char(string.byte(all, 1, -1))
