    @Test
    fun `string gsub matches utf8 text by raw bytes`() {
        val state = LuaState.create()
        LuaStdlib.openString(state)

        assertEquals(
            LuaStatus.OK,
            state.load(
                """
                local utf8 = "é"
                local wildcard, wildcardCount = string.gsub(utf8, ".", "x")
                local captured, capturedCount = string.gsub(utf8, "(.)", "[%1]")
                local functionResult, functionCount = string.gsub(utf8, ".", function(byte)
                    return string.byte(byte) .. ","
                end)
                local tableResult, tableCount = string.gsub(utf8, ".", {
                    [string.char(195)] = "A",
                    [string.char(169)] = "B",
                })
                local c1, c2, c3, c4, c5, c6 = string.byte(captured, 1, -1)
                return wildcard, wildcardCount, capturedCount, c1, c2, c3, c4, c5, c6,
                    functionResult, functionCount, tableResult, tableCount
                """.trimIndent(),
                "string-gsub-raw-bytes.lua",
            ),
        )
        assertEquals(LuaStatus.OK, state.pcall(0, -1), state.toString(-1))

        assertEquals("xx", state.toString(1))
        assertEquals(2L, state.toInteger(2))
        assertEquals(2L, state.toInteger(3))
        assertEquals(91L, state.toInteger(4))
        assertEquals(195L, state.toInteger(5))
        assertEquals(93L, state.toInteger(6))
        assertEquals(91L, state.toInteger(7))
        assertEquals(169L, state.toInteger(8))
        assertEquals(93L, state.toInteger(9))
        assertEquals("195,169,", state.toString(10))
        assertEquals(2L, state.toInteger(11))
        assertEquals("AB", state.toString(12))
        assertEquals(2L, state.toInteger(13))
    }

    @Test
    fun `string gsub preserves raw replacement bytes across replacement kinds`() {
        val state = LuaState.create()
        LuaStdlib.openString(state)

        assertEquals(
            LuaStatus.OK,
            state.load(
                """
                local direct, directCount = string.gsub(
                    "x",
                    "x",
                    string.char(0, 255, 128) .. "%0" .. "é" .. string.char(254)
                )
                local called, calledCount = string.gsub("x", "x", function()
                    return string.char(0, 255)
                end)
                local indexed, indexedCount = string.gsub("x", "x", {
                    x = string.char(128) .. "é",
                })
                local positioned, positionedCount = string.gsub("ab", "()(%a)", {
                    [1] = string.char(128),
                    [2] = "é",
                })
                local captured = string.gsub("a", "()(%a)", function(position, value)
                    return value .. position
                end)
                return direct, directCount, called, calledCount,
                    indexed, indexedCount, positioned, positionedCount, captured
                """.trimIndent(),
                "string-gsub-raw-replacements.lua",
            ),
        )
        assertEquals(LuaStatus.OK, state.pcall(0, -1), state.toString(-1))

        assertEquals(
            listOf(0, 255, 128, 'x'.code, 195, 169, 254).map(Int::toByte),
            state.toString(1)?.luaRawBytes()?.toList(),
        )
        assertEquals(1L, state.toInteger(2))
        assertEquals(listOf(0, 255).map(Int::toByte), state.toString(3)?.luaRawBytes()?.toList())
        assertEquals(1L, state.toInteger(4))
        assertEquals(listOf(128, 195, 169).map(Int::toByte), state.toString(5)?.luaRawBytes()?.toList())
        assertEquals(1L, state.toInteger(6))
        assertEquals(listOf(128, 195, 169).map(Int::toByte), state.toString(7)?.luaRawBytes()?.toList())
        assertEquals(2L, state.toInteger(8))
        assertEquals("a1", state.toString(9))
    }

