        assertEquals("Abc", state.toString(3))
        assertEquals(3L, state.toInteger(4))
        assertEquals("Fbc", state.toString(5))
        assertEquals(3L, state.toInteger(6))
        assertEquals("Nbc", state.toString(7))
        assertEquals(3L, state.toInteger(8))
    }

