    @Test
    fun `table concat reports non integer length metamethod results`() {
        val state = LuaState.create()
        LuaStdlib.openBase(state)
        LuaStdlib.openTable(state)

        assertEquals(
            LuaStatus.OK,
            state.load(
                """
                local values = setmetatable({}, {
                    __len = function()
                        return 1.5
                    end,
                })
                return table.concat(values)
                """.trimIndent(),
