        assertEquals(
            LuaStatus.OK,
            state.load(
                """
                local values = setmetatable({}, {
                    __index = function()
                        return coroutine.yield("paused")
                    end,
                })
                local co = coroutine.create(function()
                    return table.concat(values, ",", 1, 1)
                end)
                local ok, message = coroutine.resume(co)
                return ok, message, coroutine.status(co)
